#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<vector<long long>>a(n);for(int i=0;i<n;i++){a[i].resize(i+1);for(int j=0;j<=i;j++)scanf("%lld",&a[i][j]);}for(int i=1;i<n;i++)for(int j=0;j<=i;j++){long long up=(j<=i-1)?a[i-1][j]:LLONG_MIN;long long ul=(j-1>=0)?a[i-1][j-1]:LLONG_MIN;a[i][j]+=max(up,ul);}printf("%lld\n",*max_element(a[n-1].begin(),a[n-1].end()));}
